class Solution:
    def distinctPoints(self, s, k):
        n = len(s)
        move = {'U': (0, 1), 'D': (0, -1), 'L': (-1, 0), 'R': (1, 0)}
        tx = ty = 0
        for c in s:
            dx, dy = move[c]
            tx += dx
            ty += dy
        seen = set()
        for i in range(n - k + 1):
            wx = wy = 0
            for j in range(i, i + k):
                dx, dy = move[s[j]]
                wx += dx
                wy += dy
            seen.add((tx - wx, ty - wy))
        return len(seen)

