class Solution:
    def distinctPoints(self, s, k):
        n = len(s)
        move = {'U': (0, 1), 'D': (0, -1), 'L': (-1, 0), 'R': (1, 0)}
        px = [0] * (n + 1)
        py = [0] * (n + 1)
        for i, c in enumerate(s):
            dx, dy = move[c]
            px[i + 1] = px[i] + dx
            py[i + 1] = py[i] + dy
        seen = set()
        for i in range(n - k + 1):
            wx = px[i + k] - px[i]
            wy = py[i + k] - py[i]
            seen.add((wx, wy))
        return len(seen)

