var distinctPoints = function(s, k) {
    const n = s.length;
    const move = { U: [0, 1], D: [0, -1], L: [-1, 0], R: [1, 0] };
    const px = new Array(n + 1).fill(0);
    const py = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        const [dx, dy] = move[s[i]];
        px[i + 1] = px[i] + dx;
        py[i + 1] = py[i] + dy;
    }
    const seen = new Set();
    for (let i = 0; i + k <= n; i++) {
        seen.add((px[i + k] - px[i]) + ',' + (py[i + k] - py[i]));
    }
    return seen.size;
};
